sql:
SELECT metric_name, description
FROM metrics
WHERE metric_id = 1;

SELECT m.metric_name, dt.type_name
FROM metrics AS m
JOIN data_types AS dt ON m.data_type_id = dt.type_id;

SELECT m.metric_name, t.tag_name
FROM metrics m
INNER JOIN metric_tags t ON m.tag_id = t.tag_id;

SELECT metrics.metric_name, metric_tasks.task_name
FROM metrics
JOIN metric_tasks ON metrics.metric_id = metric_tasks.metric_id;

SELECT user_id 
FROM user_roles 
WHERE role_id > 0;

